import Foundation

func solve(nums: Array<Int64>): Int64 {
    var count = 0
    let n = nums.count
    for i in 0..<n {
        for j in i+1..<n {
            let a = nums[i]
            let b = nums[j]
            let absA = abs(a)
            let absB = abs(b)
            let diff = abs(a - b)
            let sum = abs(a + b)
            let minVal = min(diff, sum)
            let maxVal = max(diff, sum)
            let minAbs = min(absA, absB)
            let maxAbs = max(absA, absB)
            if minVal <= minAbs && maxVal >= maxAbs {
                count += 1
            }
        }
    }
    return Int64(count)
}
